from fastapi import FastAPI, HTTPException, Depends
from fastapi.security import OAuth2PasswordBearer, OAuth2PasswordRequestForm
import uuid

app = FastAPI()
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="login")

# This would typically come from a database
users = {
    "johndoe": {
        "username": "johndoe",
        "full_name": "John Doe",
        "hashed_password": "fakehashedsecret",
        "disabled": False,
    },
}
tokens = {}  # Empty for now

@app.post("/login")
async def login(form_data: OAuth2PasswordRequestForm = Depends()):
    user = users[form_data.username]
    if not user or not user["hashed_password"] == form_data.password:  # In real life, we'd hash the password
        raise HTTPException(status_code=400, detail="Incorrect username or password")
    
    token = str(uuid.uuid4())
    tokens[token] = user["username"]
    return {"access_token": token, "token_type": "bearer"}

@app.get("/protected_endpoint")
async def protected_endpoint(token: str = Depends(oauth2_scheme)):
    if not tokens.get(token):
        raise HTTPException(status_code=401, detail="Invalid token or expired token")
    
    return {"message": "You've reached a protected endpoint!"}